const FAVICON_BASE64 = "";

// Site background — same Uncle Sam crop as the favicon, used as an atmospheric backdrop
// site-wide. Heavily darkened via CSS overlay (not baked into the image itself) so it reads
// as mood/texture behind the real UI rather than a competing visual element.
const BACKGROUND_BASE64 = "";

function backgroundResponse() {
  const binary = atob(BACKGROUND_BASE64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new Response(bytes, {
    headers: {
      'Content-Type': 'image/jpeg',
      'Cache-Control': 'public, max-age=86400'
    }
  });
}

function faviconResponse() {
  const binary = atob(FAVICON_BASE64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new Response(bytes, {
    headers: {
      'Content-Type': 'image/jpeg',
      'Cache-Control': 'public, max-age=86400'
    }
  });
}

